if (window.innerWidth >= 993) {
    // gsap.context(() => {
    //
    //     const section = document.querySelector(".architecture");
    //     const wrapper = section.querySelector(".swiper-wrapper");
    //
    //     function getDistance() {
    //         return wrapper.scrollWidth - section.offsetWidth;
    //     }
    //
    //     gsap.to(wrapper, {
    //         x: () => -getDistance(),
    //         ease: "none",
    //         scrollTrigger: {
    //             trigger: section,
    //             start: "top top",
    //             pin: true,
    //             scrub: 1,
    //             end: () => "+=" + getDistance(),
    //             invalidateOnRefresh: true
    //         }
    //     });
    //
    // }, ".architecture");

    const section = document.querySelector(".architecture");
    const ctx = gsap.context(() => {

        const architecture = document.querySelector(".architecture .swiper-wrapper");
        const pagination = document.querySelector(".swiper-pagination");

        function getBullets() {
            return Array.from(pagination.querySelectorAll(".swiper-pagination-bullet"));
        }

        function getScrollAmount() {
            return -(architecture.scrollWidth - section.offsetWidth);
        }

        function updateActiveSlideAndPagination() {
            const slides = Array.from(architecture.children);
            const bullets = getBullets();

            const currentX = gsap.getProperty(architecture, "x") || 0;
            const viewportCenter = -currentX + window.innerWidth / 2;

            let closestIndex = 0;
            let minDelta = Infinity;

            slides.forEach((slide, index) => {
                const slideCenter = slide.offsetLeft + slide.offsetWidth / 2;
                const delta = Math.abs(slideCenter - viewportCenter);

                if (delta < minDelta) {
                    minDelta = delta;
                    closestIndex = index;
                }
            });

            slides.forEach(slide => slide.classList.remove('swiper-slide-active'));
            if (slides[closestIndex]) {
                slides[closestIndex].classList.add('swiper-slide-active');
            }

            bullets.forEach(bullet => bullet.classList.remove('swiper-pagination-bullet-active'));
            if (bullets[closestIndex]) {
                bullets[closestIndex].classList.add('swiper-pagination-bullet-active');
            }
        }

        const tween = gsap.to(architecture, {
            x: () => getScrollAmount(),
            duration: 3,
            ease: "none",
            onUpdate: updateActiveSlideAndPagination
        });

        ScrollTrigger.create({
            trigger: section,
            start: "top top",
            end: () => `+=${Math.abs(getScrollAmount())}`,
            pin: true,
            animation: tween,
            scrub: 1,
            invalidateOnRefresh: true,
            onUpdate: updateActiveSlideAndPagination
        });

        window.addEventListener('resize', updateActiveSlideAndPagination);
        updateActiveSlideAndPagination();

    }, section); // <-- scope (важно)

    gsap.context(() => {
        const section = document.querySelector(".formats");
        const wrapper = section.querySelector(".swiper-wrapper");
        const slides = Array.from(wrapper.children);

        function getSlidesPerView() {
            const w = window.innerWidth;
            if (w >= 993) return 2;
            if (w >= 577) return 1.5;
            return 1;
        }

        function getSpaceBetween() {
            const w = window.innerWidth;
            if (w >= 993) return 80;
            if (w >= 577) return 40;
            return 30;
        }

        function getDistance() {
            const slidesPerView = getSlidesPerView();
            const spaceBetween = getSpaceBetween();

            const firstSlides = slides.slice(0, slidesPerView);
            let visibleWidth = 0;
            firstSlides.forEach(slide => visibleWidth += slide.offsetWidth);
            visibleWidth += (slidesPerView - 1) * spaceBetween;

            const totalWidth = slides.reduce((sum, slide) => sum + slide.offsetWidth, 0);
            const totalSpacing = (slides.length - 1) * spaceBetween;

            return -(totalWidth + totalSpacing - visibleWidth);
        }

        gsap.to(wrapper, {
            x: () => getDistance(),
            ease: "none",
            scrollTrigger: {
                trigger: section,
                start: "bottom bottom",
                pin: true,
                scrub: 1,
                end: () => "+=" + Math.abs(getDistance()),
                invalidateOnRefresh: true
            }
        });

        window.addEventListener('resize', () => {
            ScrollTrigger.refresh();
        });

    }, ".formats");
}

